css:
* { margin: 0; padding: 0; box-sizing: border-box; }
body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; background: #0d1117; color: #e6edf3; line-height: 1.7; }
header { border-bottom: 1px solid rgba(255,255,255,0.07); position: sticky; top: 0; background: rgba(13,17,23,0.9); backdrop-filter: blur(20px); z-index: 100; }
nav { display: flex; align-items: center; justify-content: space-between; max-width: 1100px; margin: 0 auto; padding: 0 28px; height: 64px; }
.logo { font-size: 18px; font-weight: 800; color: #58a6ff; font-family: monospace; }
.nav-links { display: flex; gap: 24px; } .nav-links a { color: #8b949e; text-decoration: none; font-size: 14px; font-weight: 500; transition: color 0.2s; } .nav-links a:hover { color: #e6edf3; }
.nav-right { display: flex; gap: 8px; }
.rss { padding: 8px 14px; border-radius: 8px; border: 1px solid rgba(255,255,255,0.12); background: transparent; color: #f97316; font-size: 13px; font-weight: 700; cursor: pointer; }
.dark-toggle { width: 36px; height: 36px; border-radius: 8px; border: 1px solid rgba(255,255,255,0.12); background: transparent; cursor: pointer; font-size: 16px; }
main { max-width: 1100px; margin: 0 auto; padding: 0 28px; }
.featured { display: grid; grid-template-columns: 1fr 1fr; gap: 48px; align-items: center; padding: 56px 0; border-bottom: 1px solid rgba(255,255,255,0.07); }
.feat-tags { display: flex; gap: 8px; margin-bottom: 16px; }
.tag { padding: 4px 12px; border-radius: 20px; font-size: 12px; font-weight: 700; background: rgba(255,255,255,0.08); color: #8b949e; font-family: monospace; }
.tag.blue { background: rgba(88,166,255,0.15); color: #58a6ff; }
.featured h1 { font-size: 36px; font-weight: 800; line-height: 1.2; margin-bottom: 16px; }
.feat-content p { color: #8b949e; font-size: 16px; line-height: 1.75; margin-bottom: 24px; }
.feat-meta { display: flex; justify-content: space-between; align-items: center; }
.author { display: flex; gap: 10px; align-items: center; }
.av { width: 36px; height: 36px; border-radius: 50%; background: linear-gradient(135deg, #58a6ff, #8b5cf6); display: flex; align-items: center; justify-content: center; font-size: 12px; font-weight: 800; color: white; }
.author strong { display: block; font-size: 14px; } .author small { color: #6b7280; font-size: 12px; }
.feat-actions { display: flex; gap: 8px; }
.like-btn, .share-btn { padding: 8px 14px; border-radius: 8px; border: 1px solid rgba(255,255,255,0.1); background: rgba(255,255,255,0.04); color: #8b949e; font-size: 13px; cursor: pointer; transition: all 0.2s; } .like-btn:hover { border-color: #ef4444; color: #ef4444; }
.code-window { border-radius: 12px; overflow: hidden; border: 1px solid rgba(255,255,255,0.1); }
.cw-bar { display: flex; align-items: center; gap: 6px; padding: 12px 16px; background: rgba(255,255,255,0.04); border-bottom: 1px solid rgba(255,255,255,0.07); }
.cw-dot { width: 10px; height: 10px; border-radius: 50%; background: rgba(255,255,255,0.15); }
.cw-file { margin-left: 8px; color: #6b7280; font-size: 12px; font-family: monospace; }
.code-content { padding: 20px; font-size: 13px; font-family: monospace; line-height: 1.8; background: rgba(255,255,255,0.02); color: #e6edf3; white-space: pre; }
.c-kw { color: #ff7b72; } .c-str { color: #a5d6ff; } .c-num { color: #79c0ff; }
.posts { padding: 48px 0 60px; }
.posts-header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 28px; }
.posts-header h2 { font-size: 24px; font-weight: 800; }
.tag-filter { display: flex; gap: 6px; }
.tf { padding: 7px 16px; border-radius: 20px; border: 1px solid rgba(255,255,255,0.1); background: transparent; color: #6b7280; font-size: 13px; font-weight: 600; cursor: pointer; } .tf.active { background: #58a6ff; border-color: #58a6ff; color: white; }
.posts-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 20px; }
.post { padding: 24px; border-radius: 14px; background: rgba(255,255,255,0.03); border: 1px solid rgba(255,255,255,0.07); cursor: pointer; transition: all 0.2s; } .post:hover { border-color: rgba(88,166,255,0.3); transform: translateY(-2px); }
.post-lang { font-size: 13px; font-weight: 600; margin-bottom: 10px; }
.post h3 { font-size: 17px; font-weight: 700; margin-bottom: 8px; line-height: 1.35; } .post p { color: #6b7280; font-size: 14px; margin-bottom: 16px; line-height: 1.6; }
.post-meta { display: flex; gap: 16px; font-size: 12px; color: #4b5563; } .likes { color: #ef4444; margin-left: auto; }

js:
function like(btn) { const parts = btn.textContent.split(' '); const n = parseInt(parts[1]) + 1; btn.textContent = '♥ ' + n; btn.style.color = '#ef4444'; btn.style.borderColor = '#ef4444'; }
function toggleDark() { document.body.style.background = document.body.style.background === 'rgb(250, 250, 249)' ? '#0d1117' : '#fafaf9'; document.body.style.color = document.body.style.color === 'rgb(28, 25, 23)' ? '#e6edf3' : '#1c1917'; }
document.querySelectorAll('.tf').forEach(btn => { btn.addEventListener('click', function() { document.querySelectorAll('.tf').forEach(b => b.classList.remove('active')); this.classList.add('active'); }); });
